211 /// Return true, if evaluating \p AR at \p MaxBTC cannot wrap, because \p AR at
212 /// \p MaxBTC is guaranteed inbounds of the accessed object.
213 static bool evaluatePtrAddRecAtMaxBTCWillNotWrap(
214     const SCEVAddRecExpr *AR, const SCEV *MaxBTC, const SCEV *EltSize,
215     ScalarEvolution &SE, const DataLayout &DL, DominatorTree *DT,
216     AssumptionCache *AC,
217     std::optional<ScalarEvolution::LoopGuards> &LoopGuards) {
218   auto *PointerBase = SE.getPointerBase(AR->getStart());
219   auto *StartPtr = dyn_cast<SCEVUnknown>(PointerBase);
220   if (!StartPtr)
221     return false;
222   const Loop *L = AR->getLoop();
223   bool CheckForNonNull, CheckForFreed;
224   Value *StartPtrV = StartPtr->getValue();
225   uint64_t DerefBytes = StartPtrV->getPointerDereferenceableBytes(
226       DL, CheckForNonNull, CheckForFreed);
227 
228   if (DerefBytes && (CheckForNonNull || CheckForFreed))
229     return false;
230 
231   const SCEV *Step = AR->getStepRecurrence(SE);
232   Type *WiderTy = SE.getWiderType(MaxBTC->getType(), Step->getType());
233   const SCEV *DerefBytesSCEV = SE.getConstant(WiderTy, DerefBytes);
234 
235   // Check if we have a suitable dereferencable assumption we can use.
236   Instruction *CtxI = &*L->getHeader()->getFirstNonPHIIt();
237   if (BasicBlock *LoopPred = L->getLoopPredecessor()) {
238     if (isa<BranchInst>(LoopPred->getTerminator()))
239       CtxI = LoopPred->getTerminator();
240   }
241   RetainedKnowledge DerefRK;
242   getKnowledgeForValue(StartPtrV, {Attribute::Dereferenceable}, *AC,
243                        [&](RetainedKnowledge RK, Instruction *Assume, auto) {
244                          if (!isValidAssumeForContext(Assume, CtxI, DT))
245                            return false;
246                          if (StartPtrV->canBeFreed() &&
247                              !willNotFreeBetween(Assume, CtxI))
248                            return false;
249                          DerefRK = std::max(DerefRK, RK);
250                          return true;
251                        });
252   if (DerefRK) {
253     const SCEV *DerefRKSCEV = SE.getSCEV(DerefRK.IRArgValue);
254     // Ensure both operands have the same type
255     Type *CommonTy =
256         SE.getWiderType(DerefBytesSCEV->getType(), DerefRKSCEV->getType());
257     DerefBytesSCEV = SE.getNoopOrAnyExtend(DerefBytesSCEV, CommonTy);
258     DerefRKSCEV = SE.getNoopOrAnyExtend(DerefRKSCEV, CommonTy);
259     DerefBytesSCEV = SE.getUMaxExpr(DerefBytesSCEV, DerefRKSCEV);
260   }
261 
262   if (DerefBytesSCEV->isZero())
263     return false;
264 
265   bool IsKnownNonNegative = SE.isKnownNonNegative(Step);
266   if (!IsKnownNonNegative && !SE.isKnownNegative(Step))
267     return false;
268 
269   Step = SE.getNoopOrSignExtend(Step, WiderTy);
270   MaxBTC = SE.getNoopOrZeroExtend(MaxBTC, WiderTy);
271 
272   // For the computations below, make sure they don't unsigned wrap.
273   if (!SE.isKnownPredicate(CmpInst::ICMP_UGE, AR->getStart(), StartPtr))
274     return false;
275   const SCEV *StartOffset = SE.getNoopOrZeroExtend(
276       SE.getMinusSCEV(AR->getStart(), StartPtr), WiderTy);
277 
278   if (!LoopGuards)
279     LoopGuards.emplace(ScalarEvolution::LoopGuards::collect(AR->getLoop(), SE));
280   MaxBTC = SE.applyLoopGuards(MaxBTC, *LoopGuards);
281 
282   const SCEV *OffsetAtLastIter =
283       mulSCEVOverflow(MaxBTC, SE.getAbsExpr(Step, /*IsNSW=*/false), SE);
284   if (!OffsetAtLastIter) {
285     // Re-try with constant max backedge-taken count if using the symbolic one
286     // failed.
287     MaxBTC = SE.getConstantMaxBackedgeTakenCount(AR->getLoop());
288     if (isa<SCEVCouldNotCompute>(MaxBTC))
289       return false;
290     MaxBTC = SE.getNoopOrZeroExtend(
291         MaxBTC, WiderTy);
292     OffsetAtLastIter =
293         mulSCEVOverflow(MaxBTC, SE.getAbsExpr(Step, /*IsNSW=*/false), SE);
294     if (!OffsetAtLastIter)
295       return false;
296   }
297 
298   const SCEV *OffsetEndBytes = addSCEVNoOverflow(
299       OffsetAtLastIter, SE.getNoopOrZeroExtend(EltSize, WiderTy), SE);
300   if (!OffsetEndBytes)
301     return false;
302 
303   if (IsKnownNonNegative) {
304     // For positive steps, check if
305     //  (AR->getStart() - StartPtr) + (MaxBTC  * Step) + EltSize <= DerefBytes,
306     // while making sure none of the computations unsigned wrap themselves.
307     const SCEV *EndBytes = addSCEVNoOverflow(StartOffset, OffsetEndBytes, SE);
308     if (!EndBytes)
309       return false;
310 
311     DerefBytesSCEV = SE.applyLoopGuards(DerefBytesSCEV, *LoopGuards);
312     return SE.isKnownPredicate(CmpInst::ICMP_ULE, EndBytes, DerefBytesSCEV);
313   }
314 
315   // For negative steps check if
316   //  * StartOffset >= (MaxBTC * Step + EltSize)
317   //  * StartOffset <= DerefBytes.
318   assert(SE.isKnownNegative(Step) && "must be known negative");
319   return SE.isKnownPredicate(CmpInst::ICMP_SGE, StartOffset, OffsetEndBytes) &&
320          SE.isKnownPredicate(CmpInst::ICMP_ULE, StartOffset, DerefBytesSCEV);
321 }
