323 std::pair<const SCEV *, const SCEV *> llvm::getStartAndEndForAccess(
324     const Loop *Lp, const SCEV *PtrExpr, Type *AccessTy, const SCEV *BTC,
325     const SCEV *MaxBTC, ScalarEvolution *SE,
326     DenseMap<std::pair<const SCEV *, Type *>,
327              std::pair<const SCEV *, const SCEV *>> *PointerBounds,
328     DominatorTree *DT, AssumptionCache *AC,
329     std::optional<ScalarEvolution::LoopGuards> &LoopGuards) {
330   std::pair<const SCEV *, const SCEV *> *PtrBoundsPair;
331   if (PointerBounds) {
332     auto [Iter, Ins] = PointerBounds->insert(
333         {{PtrExpr, AccessTy},
334          {SE->getCouldNotCompute(), SE->getCouldNotCompute()}});
335     if (!Ins)
336       return Iter->second;
337     PtrBoundsPair = &Iter->second;
338   }
339 
340   const SCEV *ScStart;
341   const SCEV *ScEnd;
342 
343   auto &DL = Lp->getHeader()->getDataLayout();
344   Type *IdxTy = DL.getIndexType(PtrExpr->getType());
345   const SCEV *EltSizeSCEV = SE->getStoreSizeOfExpr(IdxTy, AccessTy);
346   if (SE->isLoopInvariant(PtrExpr, Lp)) {
347     ScStart = ScEnd = PtrExpr;
348   } else if (auto *AR = dyn_cast<SCEVAddRecExpr>(PtrExpr)) {
349     ScStart = AR->getStart();
350     if (!isa<SCEVCouldNotCompute>(BTC))
351       // Evaluating AR at an exact BTC is safe: LAA separately checks that
352       // accesses cannot wrap in the loop. If evaluating AR at BTC wraps, then
353       // the loop either triggers UB when executing a memory access with a
354       // poison pointer or the wrapping/poisoned pointer is not used.
355       ScEnd = AR->evaluateAtIteration(BTC, *SE);
356     else {
357       // Evaluating AR at MaxBTC may wrap and create an expression that is less
358       // than the start of the AddRec due to wrapping (for example consider
359       // MaxBTC = -2). If that's the case, set ScEnd to -(EltSize + 1). ScEnd
360       // will get incremented by EltSize before returning, so this effectively
361       // sets ScEnd to the maximum unsigned value for the type. Note that LAA
362       // separately checks that accesses cannot not wrap, so unsigned max
363       // represents an upper bound.
364       if (evaluatePtrAddRecAtMaxBTCWillNotWrap(AR, MaxBTC, EltSizeSCEV, *SE, DL,
365                                                DT, AC, LoopGuards)) {
366         ScEnd = AR->evaluateAtIteration(MaxBTC, *SE);
367       } else {
368         ScEnd = SE->getAddExpr(
369             SE->getNegativeSCEV(EltSizeSCEV),
370             SE->getSCEV(ConstantExpr::getIntToPtr(
371                 ConstantInt::getAllOnesValue(EltSizeSCEV->getType()),
372                 AR->getType())));
373       }
374     }
375     const SCEV *Step = AR->getStepRecurrence(*SE);
376 
377     // For expressions with negative step, the upper bound is ScStart and the
378     // lower bound is ScEnd.
379     if (const auto *CStep = dyn_cast<SCEVConstant>(Step)) {
380       if (CStep->getValue()->isNegative())
381         std::swap(ScStart, ScEnd);
382     } else {
383       // Fallback case: the step is not constant, but we can still
384       // get the upper and lower bounds of the interval by using min/max
385       // expressions.
386       ScStart = SE->getUMinExpr(ScStart, ScEnd);
387       ScEnd = SE->getUMaxExpr(AR->getStart(), ScEnd);
388     }
389   } else
390     return {SE->getCouldNotCompute(), SE->getCouldNotCompute()};
391 
392   assert(SE->isLoopInvariant(ScStart, Lp) && "ScStart needs to be invariant");
393   assert(SE->isLoopInvariant(ScEnd, Lp) && "ScEnd needs to be invariant");
394 
395   // Add the size of the pointed element to ScEnd.
396   ScEnd = SE->getAddExpr(ScEnd, EltSizeSCEV);
397 
398   std::pair<const SCEV *, const SCEV *> Res = {ScStart, ScEnd};
399   if (PointerBounds)
400     *PtrBoundsPair = Res;
401   return Res;
402 }
