4880   if (Ops.size() == 1)
4881     return Ops[0];
4882 
4883   // Find the max type first.
4884   Type *MaxType = nullptr;
4885   for (const auto *S : Ops)
4886     if (MaxType)
4887       MaxType = getWiderType(MaxType, S->getType());
4888     else
4889       MaxType = S->getType();
