4056   RetVal visitAnyMinMaxExpr(const SCEV *S) {
4057     assert((isa<SCEVMinMaxExpr>(S) || isa<SCEVSequentialMinMaxExpr>(S)) &&
4058            "Only for min/max expressions.");
